from dataclasses import dataclass
from typing import Any

@dataclass
class TenantIsolatedRetrieval:
    vector_store: Any   # Pinecone / Qdrant / Weaviate client
    tenant_id: str

    def retrieve(self, query_embedding: list[float], top_k: int = 5) -> list[dict]:
        # CRITICAL: tenant_id filter MUST be applied at query time.
        # Never allow a query without this filter — even for admins.
        results = self.vector_store.query(
            vector=query_embedding,
            top_k=top_k,
            filter={"tenant_id": {"$eq": self.tenant_id}},  # Pinecone syntax
        )
        # Verify filter was honoured (defence-in-depth)
        for chunk in results.get("matches", []):
            if chunk["metadata"].get("tenant_id") != self.tenant_id:
                raise SecurityError(
                    f"Cross-tenant data leak prevented: "
                    f"chunk tenant={chunk['metadata'].get('tenant_id')}, "
                    f"query tenant={self.tenant_id}"
                )
        return results.get("matches", [])

class SecurityError(Exception):
    pass

# Also: use separate namespaces or collections per tenant for hard isolation.
# Metadata filter is a soft control; namespace separation is a hard control.

import re
from dataclasses import dataclass

_PII_PATTERNS = [
    re.compile(r'[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}'),  # email
    re.compile(r'\b\d{3}[-.]?\d{2}[-.]?\d{4}\b'),  # SSN
    re.compile(r'\b(?:\d[ -]?){13,16}\b'),             # credit card
]

def scrub_history_pii(messages: list[dict]) -> list[dict]:
    scrubbed = []
    for msg in messages:
        content = msg.get("content", "")
        for pat in _PII_PATTERNS:
            content = pat.sub("[PII_REDACTED]", content)
        scrubbed.append({**msg, "content": content})
    return scrubbed

# Session isolation: enforce that session_id is bound to user_id
def validate_session_ownership(session_id: str, user_id: str, session_store) -> None:
    session = session_store.get(session_id)
    if session is None:
        raise ValueError(f"Session {session_id} not found")
    if session["owner_user_id"] != user_id:
        raise SecurityError(
            f"Session {session_id} belongs to {session['owner_user_id']}, "
            f"not {user_id}"
        )

class SecurityError(Exception):
    pass

from urllib.parse import urlparse
from dataclasses import dataclass

@dataclass
class URLAllowlistGuard:
    allowed_domains: set[str]

    def validate(self, url: str) -> None:
        parsed = urlparse(url)
        domain = parsed.netloc.lower()

        # Strip port numbers for comparison
        domain = domain.split(":")[0]

        if not any(
            domain == allowed or domain.endswith("." + allowed)
            for allowed in self.allowed_domains
        ):
            raise SecurityError(
                f"Tool URL blocked: {domain} not in allowlist. "
                "Possible exfiltration attempt."
            )

        # Block dynamic query params that may encode exfiltrated data
        if parsed.query and len(parsed.query) > 200:
            raise SecurityError(
                f"URL query string suspiciously long ({len(parsed.query)} chars) — "
                "possible data exfiltration via URL encoding."
            )

# Enforce on every tool call that takes a URL parameter
guard = URLAllowlistGuard(allowed_domains={"company.com", "approved-api.io"})
try:
    guard.validate("https://attacker.com/?data=SYSTEM_PROMPT_HERE")
except SecurityError as e:
    print(f"BLOCKED: {e}")

class SecurityError(Exception):
    pass

from dataclasses import dataclass
from enum import Enum

class Role(Enum):
    VIEWER = "viewer"
    USER = "user"
    ADMIN = "admin"

# RBAC table for tools — checked at execution, not at LLM output
TOOL_RBAC: dict[str, set[Role]] = {
    "search_docs":      {Role.VIEWER, Role.USER, Role.ADMIN},
    "read_document":    {Role.VIEWER, Role.USER, Role.ADMIN},
    "create_document":  {Role.USER, Role.ADMIN},
    "update_document":  {Role.USER, Role.ADMIN},
    "delete_document":  {Role.ADMIN},
    "list_users":       {Role.ADMIN},
    "send_email":       {Role.USER, Role.ADMIN},
}

@dataclass
class ToolExecutor:
    user_role: Role

    def execute(self, tool_name: str, parameters: dict) -> dict:
        allowed = TOOL_RBAC.get(tool_name, set())
        if self.user_role not in allowed:
            raise PermissionError(
                f"SECURITY: {self.user_role.value} cannot call {tool_name}. "
                "This may be a privilege escalation attempt via prompt injection."
            )
        # ... actual tool execution ...
        return {"status": "ok"}

# The check happens in the EXECUTOR, not in the LLM output parser.
# The model can output any tool call — the executor enforces permissions.
executor = ToolExecutor(user_role=Role.VIEWER)
try:
    executor.execute("delete_document", {"id": "doc_123"})
except PermissionError as e:
    print(e)

from dataclasses import dataclass
import re

# Patterns that should never appear in persisted memory
_MEMORY_INJECTION_PATTERNS = [
    re.compile(r'(?i)next\s+(session|time).*?(send|email|forward|transmit)'),
    re.compile(r'(?i)(always|every\s+session).*?(ignore|override|forget)\s+instructions'),
    re.compile(r'(?i)remember\s+to.*?(call|invoke|execute)\s+\w+_tool'),
]

@dataclass
class SafeMemoryStore:
    _store: dict = None

    def __post_init__(self):
        self._store = {}

    def write(self, key: str, value: str, author: str) -> None:
        for pat in _MEMORY_INJECTION_PATTERNS:
            if pat.search(value):
                raise SecurityError(
                    f"Memory write blocked: injection pattern detected "
                    f"(key={key}, author={author})"
                )
        # Flag autonomous memory writes for human review
        if author == "model":
            self._store[f"__pending_review__{key}"] = value
            # Queue for human approval before activating
        else:
            self._store[key] = value

    def read(self, key: str) -> str | None:
        # Never surface pending-review entries to the model
        if key.startswith("__pending_review__"):
            return None
        return self._store.get(key)

class SecurityError(Exception):
    pass
